12#RQ:export default async function orderCreatedHandler({
13#NY:  event,
14#PT:  container
15#XY:}: SubscriberArgs<{ id: string }>) {
16#WV:  const notificationService = container.resolve(Modules.NOTIFICATION)
17#HX:
18#JZ:  const query = container.resolve(ContainerRegistrationKeys.QUERY)
19#SZ:  const {
20#QQ:    data: [order]
21#SZ:  } = await query.graph({
22#ZM:    entity: 'order',
23#QZ:    fields: [
24#BP:      '*',
25#WS:      'customer.*',
26#WV:      'items.*',
27#TP:      'shipping_address.*',
28#QH:      'shipping_methods.*',
29#BW:      'summary.*'
30#ZP:    ],
31#KY:    filters: {
32#QH:      id: event.data.id
33#NH:    }
34#YV:  })
35#TX:
36#YJ:  if (!order) {
37#VB:    return
38#HW:  }
39#MS:
40#TX:  await notificationService.createNotifications({
41#MJ:    to: order.email,
42#YW:    channel: 'email',
43#YR:    template: ResendNotificationTemplates.BUYER_NEW_ORDER,
44#YT:    content: {
45#PT:      subject: `Order Confirmation - #${order.display_id}`
46#BY:    },
47#JJ:    data: {
48#PW:      data: {
49#SX:        user_name: order.customer?.first_name || 'Customer',
50#YK:        order_id: order.id,
51#WY:        order_address: buildHostAddress(
52#QH:          Hosts.STOREFRONT,
53#XZ:          `/user/orders/${order.id}`
54#VW:        ).toString(),
55#ZT:        order: {
56#QV:          ...order,
57#HQ:          display_id: order.display_id,
58#JS:          total: order.summary?.current_order_total || 0
59#ST:        }
60#HW:      }
61#KK:    }
62#QV:  })
63#SP:}
