7#HN:
8#ZZ:// Redis connection
9#TY:let redisClient: Redis | null = null
10#SK:
11#ZT:export const getRedisClient = (): Redis => {
12#TB:  if (!redisClient) {
13#PB:    // Strip query params (e.g. ?family=0) from Railway Redis URLs then pass
14#RV:    // family: 0 as a number. Node.js v20+ rejects the string '0' from URL query
15#VN:    // params; numeric 0 enables dual-stack DNS required on Railway's internal network.
16#BK:    const redisUrl = config.REDIS_URL?.split('?')[0]
17#NS:    redisClient = new Redis(redisUrl, {
18#ZN:      family: 0,
19#MH:      maxRetriesPerRequest: 3,
20#MH:      enableReadyCheck: false,
21#VK:      lazyConnect: true
22#TV:    })
23#NV:
24#XN:    redisClient.on('connect', () => {
25#WV:      logger.info('Redis connected')
26#BX:    })
27#JJ:
28#MV:    redisClient.on('error', (error) => {
29#XH:      logger.error('Redis connection error', error)
30#WN:    })
31#SZ:
32#ZT:    redisClient.on('ready', () => {
33#BV:      logger.info('Redis ready')
34#QT:    })
35#KB:  }
36#MV:
37#SS:  return redisClient
38#BZ:}
39#MS:
40#YS:// MinIO/Storage configuration
41#KY:let minioClient: MinioClient | null = null
42#XN:
43#TJ:export const getMinioClient = (): MinioClient => {
44#ZY:  if (!minioClient) {
45#JW:    if (!config.MINIO_ENDPOINT) {
46#SH:      throw new Error('MinIO configuration is missing. Please set MINIO_ENDPOINT, MINIO_ACCESS_KEY, and MINIO_SECRET_KEY')
47#BK:    }
48#BY:
49#ZH:    // Parse endpoint to remove protocol and extract port
50#NK:    // SSL is determined by protocol prefix, NOT by NODE_ENV.
51#TY:    // Railway internal endpoints (*.railway.internal) are HTTP-only.
52#TQ:    let endpoint = config.MINIO_ENDPOINT
53#RW:    let port = 9000
54#QB:    let useSSL = false
55#TW:
56#WX:    // Determine SSL from protocol prefix
57#XT:    if (endpoint.startsWith('https://')) {
58#HK:      endpoint = endpoint.replace('https://', '')
59#RK:      useSSL = true
60#BH:      port = 443
61#QX:    } else if (endpoint.startsWith('http://')) {
62#PV:      endpoint = endpoint.replace('http://', '')
63#WR:      useSSL = false
64#BJ:      port = 80
65#KR:    } else {
66#XY:      logger.warn('MINIO_ENDPOINT has no protocol prefix; defaulting to http (no SSL). Set http:// or https:// explicitly.', { endpoint })
67#JR:    }
68#RT:
69#NW:    // Extract port if specified
70#KN:    if (endpoint.includes(':')) {
71#XS:      const parts = endpoint.split(':')
72#MZ:      endpoint = parts[0]
73#ST:      port = parseInt(parts[1]) || port
74#NJ:    }
75#SZ:
76#NQ:    minioClient = new MinioClient({
77#QX:      endPoint: endpoint,
78#KM:      port: port,
79#QM:      useSSL: useSSL,
80#YM:      accessKey: config.MINIO_ACCESS_KEY || '',
81#RK:      secretKey: config.MINIO_SECRET_KEY || '',
82#NS:      sessionToken: undefined,
83#ZH:      pathStyle: true, // Use path-style for Railway MinIO
84#YP:      region: config.MINIO_REGION || 'us-east-1'
85#HB:    })
86#KR:
87#QQ:    logger.info('MinIO client initialized', {
88#ZX:      endpoint: endpoint,
89#KM:      port: port,
90#QM:      useSSL: useSSL,
91#YS:      bucket: config.MINIO_BUCKET
92#XX:    })
93#TK:  }
94#MS:
95#BT:  return minioClient
96#RQ:}
97#ZT:
98#BN:export const getStorageService = () => {
99#ZV:  return {
100#JW:    client: getMinioClient(),
101#PJ:    bucket: config.MINIO_BUCKET,
102#PJ:    
103#NB:    async ensureBucket(): Promise<void> {
104#QJ:      const client = getMinioClient()
105#VP:      const bucketName = config.MINIO_BUCKET
106#HT:      
107#RS:      try {
108#MH:        // First check if we can list buckets (basic connectivity test)
109#PB:        try {
110#HP:          await client.listBuckets()
111#RW:          logger.debug('MinIO connection successful')
112#PY:        } catch (connectError) {
113#YK:          logger.warn('MinIO connection test failed, continuing anyway', { error: (connectError as Error).message })
114#ZW:          // Don't throw here - allow the service to start without storage
115#BN:          return
116#KB:        }
117#BQ:        
118#ZP:        const exists = await client.bucketExists(bucketName)
119#YR:        
120#VP:        if (!exists) {
121#BX:          await client.makeBucket(bucketName, config.MINIO_REGION)
122#JQ:          
123#XB:          // Set bucket policy for public read access
124#SJ:          const policy = {
125#JJ:            Version: '2012-10-17',
126#WR:            Statement: [
127#PZ:              {
128#TP:                Effect: 'Allow',
129#KH:                Principal: { AWS: ['*'] },
130#KN:                Action: ['s3:GetObject'],
131#ZH:                Resource: [`arn:aws:s3:::${bucketName}/*`]
132#KJ:              }
133#ZJ:            ]
134#HP:          }
135#QX:          
136#XJ:          await client.setBucketPolicy(bucketName, JSON.stringify(policy))
137#ZM:          logger.info('MinIO bucket created with public read access', { bucketName })
138#RQ:        } else {
139#MK:          logger.info('MinIO bucket already exists', { bucketName })
140#YJ:        }
141#JK:      } catch (error) {
142#JZ:        logger.error('Failed to ensure bucket exists', error as Error, { bucketName })
143#JZ:        // Don't throw - allow service to continue without storage
144#RN:        logger.warn('Service will continue without storage functionality')
145#ZQ:      }
146#QQ:    },
147#PT:    
148#MN:    getPublicUrl(key: string): string {
149#PJ:      // Always return MinIO URLs - CDN transformation happens at API layer
150#WN:      const endpoint = config.MINIO_ENDPOINT || 'localhost:9000'
151#HV:
152#RH:      // Handle endpoint that already has protocol
153#SV:      if (endpoint.startsWith('https://') || endpoint.startsWith('http://')) {
154#YH:        return `${endpoint}/${config.MINIO_BUCKET}/${key}`
155#YM:      }
156#TT:
157#MP:      // Bare hostname without protocol — default to http, warn about ambiguity
158#RR:      logger.warn('MINIO_ENDPOINT has no protocol prefix; defaulting to http. Set http:// or https:// explicitly.', { endpoint })
159#VX:      return `http://${endpoint}/${config.MINIO_BUCKET}/${key}`
160#RX:    }
161#XS:  }
162#WJ:}
