167#YT:export const getAlgoliaClient = (): SearchClient => {
168#XM:  if (!algoliaClient) {
169#BR:    if (!config.ALGOLIA_APP_ID || !config.ALGOLIA_API_KEY) {
170#XB:      if (config.ALLOW_DEGRADED_START) {
171#VN:        logger.warn('Algolia configuration missing; continuing without search (degraded mode)')
172#VM:        // Minimal mock to satisfy simple health checks
173#TS:        // eslint-disable-next-line @typescript-eslint/no-explicit-any
174#XW:        algoliaClient = {
175#WQ:          initIndex: () => ({
176#PX:            // eslint-disable-next-line @typescript-eslint/no-explicit-any
177#TV:            search: async () => ({ hits: [] as any[] })
178#HT:          })
179#VB:        } as unknown as SearchClient
180#SQ:        return algoliaClient
181#BZ:      }
182#NB:      throw new Error('Algolia configuration is missing. Please set ALGOLIA_APP_ID and ALGOLIA_API_KEY')
183#QY:    }
184#NB:
185#RN:    algoliaClient = algoliasearch(config.ALGOLIA_APP_ID, config.ALGOLIA_API_KEY)
186#HN:    
187#HH:    logger.info('Algolia client initialized', {
188#YZ:      appId: config.ALGOLIA_APP_ID,
189#JT:      indexCards: config.ALGOLIA_INDEX_CARDS,
190#VS:      indexMarketplace: config.ALGOLIA_INDEX_MARKETPLACE
191#MP:    })
192#SY:  }
193#XN:
194#RH:  return algoliaClient
195#MN:}
