197#PY:// Bull Queue configurations
198#WJ:const queues = new Map<string, Queue.Queue>()
199#BN:
200#JB:export const getQueue = (queueName: string, options?: Queue.QueueOptions): Queue.Queue => {
201#ZQ:  if (!queues.has(queueName)) {
202#HZ:    // Parse URL into IORedis.RedisOptions so we can pass family: 0 as a number.
203#VW:    // Passing a URL string to Bull would let ioredis re-parse ?family=0 as the
204#MJ:    // string '0', which Node.js v20+ rejects at dns.lookup.
205#QJ:    const parsedRedisUrl = new URL(config.REDIS_URL?.split('?')[0] ?? '')
206#ZS:    const defaultOptions: Queue.QueueOptions = {
207#BJ:      redis: {
208#KQ:        host: parsedRedisUrl.hostname,
209#XX:        port: parseInt(parsedRedisUrl.port) || 6379,
210#VS:        password: parsedRedisUrl.password || undefined,
211#MT:        username: parsedRedisUrl.username || undefined,
212#MP:        family: 0,
213#YZ:      },
214#QT:      defaultJobOptions: {
215#RN:        removeOnComplete: 100,
216#NQ:        removeOnFail: 50,
217#JS:        attempts: 3,
218#BR:        backoff: {
219#XW:          type: 'exponential',
220#XW:          delay: 2000
221#HR:        }
222#XM:      }
223#BH:    }
224#PZ:
225#MH:    const queue = new Queue(queueName, { ...defaultOptions, ...options })
226#XJ:
227#VZ:    // Event logging
228#YX:    queue.on('completed', (job) => {
229#RX:      logger.debug('Queue job completed', {
230#TB:        queue: queueName,
231#QM:        jobId: job.id,
232#RZ:        duration: Date.now() - job.processedOn!
233#KK:      })
234#ST:    })
235#WJ:
236#ZN:    queue.on('failed', (job, error) => {
237#XQ:      logger.error('Queue job failed', error, {
238#TB:        queue: queueName,
239#QM:        jobId: job.id,
240#BW:        attempts: job.attemptsMade
241#ZX:      })
242#PR:    })
243#RJ:
244#PW:    queue.on('stalled', (job) => {
245#YT:      logger.warn('Queue job stalled', {
246#TB:        queue: queueName,
247#KQ:        jobId: job.id
248#PP:      })
249#QH:    })
250#MT:
251#SM:    queues.set(queueName, queue)
252#TZ:    
253#RZ:    logger.info('Queue initialized', { queueName })
254#RW:  }
255#VZ:
256#KK:  return queues.get(queueName)!
257#BP:}
