316#JJ:// Health check functions
317#KY:export const checkRedisHealth = async (): Promise<{ healthy: boolean; error?: string }> => {
318#JQ:  try {
319#ZB:    const redis = getRedisClient()
320#QH:    await redis.ping()
321#RX:    return { healthy: true }
322#QB:  } catch (error) {
323#SZ:    return { healthy: false, error: (error as Error).message }
324#VX:  }
325#QY:}
326#MV:
327#MZ:export const checkStorageHealth = async (): Promise<{ healthy: boolean; error?: string }> => {
328#JQ:  try {
329#PY:    if (!config.MINIO_ENDPOINT || !config.MINIO_ACCESS_KEY || !config.MINIO_SECRET_KEY) {
330#RT:      return { healthy: false, error: 'Storage configuration incomplete' }
331#BM:    }
332#YP:    
333#JK:    const storage = getStorageService()
334#RY:    
335#VQ:    // Add timeout to storage health check
336#HW:    await Promise.race([
337#MM:      storage.ensureBucket(),
338#QZ:      new Promise((_, reject) => 
339#ST:        setTimeout(() => reject(new Error('Storage health check timeout')), 5000)
340#HS:      )
341#TQ:    ])
342#ZH:    
343#RX:    return { healthy: true }
344#QB:  } catch (error) {
345#SZ:    return { healthy: false, error: (error as Error).message }
346#MN:  }
347#TZ:}
348#BQ:
349#MX:export const checkAlgoliaHealth = async (): Promise<{ healthy: boolean; error?: string }> => {
350#JQ:  try {
351#NZ:    const algolia = getAlgoliaClient()
352#RY:    const index = algolia.initIndex(config.ALGOLIA_INDEX_CARDS)
353#JR:    
354#RR:    // Simple search to check if Algolia is responding
355#YS:    await index.search('', { hitsPerPage: 1 })
356#RX:    return { healthy: true }
357#QB:  } catch (error) {
358#SZ:    return { healthy: false, error: (error as Error).message }
359#WN:  }
360#JH:}
361#BR:
362#HN:export const checkQueueHealth = async (queueName: string): Promise<{ healthy: boolean; error?: string }> => {
363#JQ:  try {
364#WZ:    const queue = getQueue(queueName)
365#HY:    const stats = await queue.getJobCounts()
366#MB:    
367#NY:    // Queue is healthy if we can get stats
368#RX:    return { healthy: true }
369#QB:  } catch (error) {
370#SZ:    return { healthy: false, error: (error as Error).message }
371#RB:  }
372#TQ:}
