374#KM:// Cleanup function for graceful shutdown
375#WJ:export const closeInfrastructure = async (): Promise<void> => {
376#KS:  logger.info('Closing infrastructure connections...')
377#VN:
378#HQ:  // Close Redis
379#JY:  if (redisClient) {
380#QS:    await redisClient.quit()
381#ZW:    redisClient = null
382#YB:    logger.info('Redis connection closed')
383#HR:  }
384#ZY:
385#WJ:  // Close queues
386#KN:  for (const [name, queue] of queues) {
387#MP:    await queue.close()
388#YT:    logger.info('Queue closed', { queue: name })
389#HR:  }
390#JK:  queues.clear()
391#XV:
392#XM:  // Note: MinIO client doesn't need explicit closing
393#YP:  // Algolia client doesn't need explicit closing
394#KP:
395#XR:  logger.info('All infrastructure connections closed')
396#QB:}
397#NT:
398#XZ:// Initialize all infrastructure
399#MT:export const initializeInfrastructure = async (): Promise<void> => {
400#PT:  logger.info('Initializing infrastructure...')
401#MJ:
402#JQ:  try {
403#XB:    // Initialize Redis
404#ZB:    const redis = getRedisClient()
405#VN:    try {
406#TH:      await redis.ping()
407#ZQ:      logger.info('Redis initialized')
408#MQ:    } catch (e) {
409#XB:      if (config.ALLOW_DEGRADED_START) {
410#YV:        logger.warn('Redis not available; continuing without cache (degraded mode)')
411#PM:      } else {
412#WQ:        throw e
413#PV:      }
414#YM:    }
415#QW:
416#PJ:    // Initialize storage with timeout and completely non-blocking approach
417#NK:    if (config.MINIO_ENDPOINT && config.MINIO_ACCESS_KEY && config.MINIO_SECRET_KEY) {
418#JX:      // Start storage initialization in background - don't wait for it
419#PW:      const initializeStorageAsync = async () => {
420#PB:        try {
421#QV:          // Set a longer timeout for Railway environment (30 seconds)
422#PW:          const storage = getStorageService()
423#YN:          const storageInitPromise = storage.ensureBucket()
424#PX:          
425#NK:          // Use Promise.race to implement a timeout - increased to 30 seconds for Railway
426#MT:          await Promise.race([
427#ZP:            storageInitPromise,
428#BK:            new Promise((_, reject) => 
429#TM:              setTimeout(() => reject(new Error('Storage initialization timeout after 30 seconds')), 30000)
430#RW:            )
431#MN:          ])
432#WS:          
433#VM:          logger.info('Storage initialized successfully (background)')
434#KQ:        } catch (error) {
435#HQ:          logger.error('Storage initialization failed (background)', error as Error)
436#YT:          logger.warn('Server will continue without storage - images may not load until storage is available')
437#YY:          
438#KK:          // Retry storage initialization after a delay if it fails
439#PP:          setTimeout(() => {
440#HR:            logger.info('Retrying storage initialization...')
441#ZM:            initializeStorageAsync().catch(err => {
442#QX:              logger.error('Storage retry failed', err as Error)
443#XX:            })
444#VW:          }, 60000) // Retry after 1 minute
445#WS:        }
446#TS:      }
447#SV:      
448#HT:      // Start in background without blocking
449#YS:      initializeStorageAsync()
450#YB:      logger.info('Storage initialization started in background')
451#KR:    } else {
452#KK:      logger.warn('Storage configuration incomplete - skipping MinIO initialization')
453#TX:    }
454#TS:
455#ZK:    // Initialize Algolia (connection is lazy)
456#VN:    try {
457#BN:      getAlgoliaClient()
458#MV:      logger.info('Algolia initialized')
459#MQ:    } catch (e) {
460#XB:      if (config.ALLOW_DEGRADED_START) {
461#BW:        logger.warn('Algolia not configured; continuing without search (degraded mode)')
462#PM:      } else {
463#WQ:        throw e
464#RS:      }
465#SN:    }
466#JX:
467#NT:    // Test queue initialization
468#KN:    getETLQueue()
469#VN:    getImageQueue()
470#MZ:    getSearchIndexQueue()
471#QY:    getPriceUpdateQueue()
472#TB:    logger.info('Queues initialized')
473#JM:
474#NS:    logger.info('All infrastructure initialized successfully')
475#QB:  } catch (error) {
476#KX:    logger.error('Failed to initialize infrastructure', error as Error)
477#XH:    if (!config.ALLOW_DEGRADED_START) {
478#RS:      throw error
479#KW:    }
480#VK:  }
481#NR:}
