import { SubscriberArgs, SubscriberConfig } from '@medusajs/framework'
import {
  ContainerRegistrationKeys,
  FulfillmentWorkflowEvents
} from '@medusajs/framework/utils'
import Redis from 'ioredis'

const LOG_PREFIX = '[collection-auto-update]'
const REDIS_CHANNEL = 'order.receipt.confirmed'

let redisPublisher: Redis | null = null

function getRedisPublisher(): Redis {
  if (!redisPublisher) {
    const redisUrl = (process.env.REDIS_URL || 'redis://localhost:6379').split(
      '?'
    )[0]
    redisPublisher = new Redis(redisUrl, {
      family: 0,
      maxRetriesPerRequest: 3,
      lazyConnect: true
    })
  }
  return redisPublisher
}

interface CollectionUpdateItem {
  catalogSku: string
  quantity: number
  condition: string
}

interface CollectionUpdatePayload {
  userId: string
  items: CollectionUpdateItem[]
}

export default async function collectionAutoUpdateHandler({
  event,
  container
}: SubscriberArgs<{ id: string }>) {
  const fulfillmentId = event.data.id
  const logger = container.resolve(ContainerRegistrationKeys.LOGGER)

  logger.info(
    `${LOG_PREFIX} Processing delivery.created for fulfillment ${fulfillmentId}`
  )

  try {
    const query = container.resolve(ContainerRegistrationKeys.QUERY)

    const {
      data: [fulfillment]
    } = await query.graph({
      entity: 'fulfillment',
      fields: [
        'order.id',
        'order.customer_id',
        'order.items.*',
        'order.items.variant.*',
        'order.items.variant.product.*'
      ],
      filters: {
        id: fulfillmentId
      }
    })

    if (!fulfillment?.order) {
      logger.warn(
        `${LOG_PREFIX} No order found for fulfillment ${fulfillmentId}`
      )
      return
    }

    const order = fulfillment.order
    const userId = order.customer_id

    if (!userId) {
      logger.warn(
        `${LOG_PREFIX} No customer_id on order ${order.id} for fulfillment ${fulfillmentId}`
      )
      return
    }

    const items: CollectionUpdateItem[] = []

    for (const item of order.items || []) {
      // Extract catalog_sku from product metadata or variant metadata
      const productMetadata = item.variant?.product?.metadata || {}
      const variantMetadata = item.variant?.metadata || {}

      const catalogSku =
        (productMetadata as Record<string, unknown>).catalog_sku ||
        (variantMetadata as Record<string, unknown>).catalog_sku

      if (!catalogSku) {
        logger.debug(
          `${LOG_PREFIX} Skipping item ${item.id} — no catalog_sku in metadata`
        )
        continue
      }

      const condition =
        ((variantMetadata as Record<string, unknown>).condition as string) ||
        'NM'
      const quantity = item.quantity || 1

      items.push({
        catalogSku: String(catalogSku),
        quantity,
        condition
      })
    }

    if (items.length === 0) {
      logger.info(
        `${LOG_PREFIX} No items with catalog_sku found for fulfillment ${fulfillmentId}`
      )
      return
    }

    const payload: CollectionUpdatePayload = { userId, items }

    const redis = getRedisPublisher()
    await redis.publish(REDIS_CHANNEL, JSON.stringify(payload))

    logger.info(
      `${LOG_PREFIX} Published ${items.length} item(s) to ${REDIS_CHANNEL} for user ${userId}`
    )
  } catch (error) {
    logger.error(
      `${LOG_PREFIX} Error processing fulfillment ${fulfillmentId}: ${(error as Error).message}`
    )
    // Swallow error — don't block order flow
  }
}

export const config: SubscriberConfig = {
  event: FulfillmentWorkflowEvents.DELIVERY_CREATED,
  context: {
    subscriberId: 'collection-auto-update-handler'
  }
}

