import { getRedisSubscriber } from '../config/infrastructure'
import { AppDataSource } from '../config/database'
import { Collection } from '../entities/Collection'
import { CollectionCard } from '../entities/CollectionCard'
import { CatalogSKU } from '../entities/CatalogSKU'
import { logger } from '../config/logger'

const LOG_PREFIX = '[collection-subscriber]'
const REDIS_CHANNEL = 'order.receipt.confirmed'

interface CollectionUpdateItem {
  catalogSku: string
  quantity: number
  condition: string
}

interface CollectionUpdatePayload {
  userId: string
  items: CollectionUpdateItem[]
}

function isValidPayload(data: unknown): data is CollectionUpdatePayload {
  if (!data || typeof data !== 'object') return false
  const obj = data as Record<string, unknown>
  if (typeof obj.userId !== 'string' || !obj.userId) return false
  if (!Array.isArray(obj.items)) return false
  return obj.items.every(
    (item: unknown) =>
      item &&
      typeof item === 'object' &&
      typeof (item as Record<string, unknown>).catalogSku === 'string' &&
      typeof (item as Record<string, unknown>).quantity === 'number'
  )
}

async function handleMessage(message: string): Promise<void> {
  let payload: CollectionUpdatePayload

  try {
    payload = JSON.parse(message)
  } catch {
    logger.warn(`${LOG_PREFIX} Malformed JSON received, skipping`)
    return
  }

  if (!isValidPayload(payload)) {
    logger.warn(`${LOG_PREFIX} Invalid payload shape, skipping`)
    return
  }

  const { userId, items } = payload

  logger.info(
    `${LOG_PREFIX} Processing ${items.length} item(s) for user ${userId}`
  )

  try {
    await AppDataSource.transaction(async (manager) => {
      const collectionRepo = manager.getRepository(Collection)
      const collectionCardRepo = manager.getRepository(CollectionCard)
      const catalogSkuRepo = manager.getRepository(CatalogSKU)

      // Find or create user's personal collection
      let collection = await collectionRepo.findOne({
        where: { userId, type: 'personal', name: 'My Collection' }
      })

      if (!collection) {
        collection = collectionRepo.create({
          userId,
          name: 'My Collection',
          type: 'personal',
          isPublic: false
        })
        collection = await collectionRepo.save(collection)
        logger.info(
          `${LOG_PREFIX} Created "My Collection" for user ${userId}`
        )
      }

      for (const item of items) {
        try {
          // Resolve catalogSku to a card ID via CatalogSKU entity
          const catalogSkuRecord = await catalogSkuRepo.findOne({
            where: { sku: item.catalogSku },
            relations: ['print', 'print.card']
          })

          const cardId = catalogSkuRecord?.print?.card?.id
          if (!cardId) {
            logger.warn(
              `${LOG_PREFIX} No card found for catalogSku ${item.catalogSku}, skipping`
            )
            continue
          }

          const condition = item.condition || 'NM'

          // Check for existing CollectionCard with same SKU + condition
          let collectionCard = await collectionCardRepo.findOne({
            where: {
              collectionId: collection.id,
              cardId,
              catalogSku: item.catalogSku,
              condition: condition as CollectionCard['condition']
            }
          })

          if (collectionCard) {
            // Increment quantity
            collectionCard.quantity += item.quantity
            await collectionCardRepo.save(collectionCard)
            logger.info(
              `${LOG_PREFIX} Incremented quantity for ${item.catalogSku} (condition: ${condition}) to ${collectionCard.quantity}`
            )
          } else {
            // Create new CollectionCard
            collectionCard = collectionCardRepo.create({
              collectionId: collection.id,
              cardId,
              catalogSku: item.catalogSku,
              quantity: item.quantity,
              condition: condition as CollectionCard['condition'],
              language: 'EN',
              isForTrade: false,
              acquiredDate: new Date()
            })
            await collectionCardRepo.save(collectionCard)
            logger.info(
              `${LOG_PREFIX} Added ${item.catalogSku} (condition: ${condition}) to collection`
            )
          }
        } catch (itemError) {
          logger.error(
            `${LOG_PREFIX} Error processing item ${item.catalogSku} for user ${userId}: ${(itemError as Error).message}`
          )
          // Continue with remaining items
        }
      }
    })
  } catch (error) {
    logger.error(
      `${LOG_PREFIX} Error upserting collection for user ${userId}: ${(error as Error).message}`
    )
  }
}

export function startCollectionSubscriber(): void {
  const subscriber = getRedisSubscriber()

  subscriber.subscribe(REDIS_CHANNEL, (err) => {
    if (err) {
      logger.error(
        `${LOG_PREFIX} Failed to subscribe to ${REDIS_CHANNEL}: ${err.message}`
      )
      return
    }
    logger.info(`${LOG_PREFIX} Subscribed to ${REDIS_CHANNEL}`)
  })

  subscriber.on('message', (channel: string, message: string) => {
    if (channel !== REDIS_CHANNEL) return
    handleMessage(message).catch((err) => {
      logger.error(
        `${LOG_PREFIX} Unhandled error in message handler: ${(err as Error).message}`
      )
    })
  })
}

