import collectionAutoUpdateHandler from '../collection-auto-update'

// Mock ioredis
const mockPublish = jest.fn().mockResolvedValue(1)
jest.mock('ioredis', () => {
  return jest.fn().mockImplementation(() => ({
    publish: mockPublish,
    on: jest.fn(),
    connect: jest.fn().mockResolvedValue(undefined)
  }))
})

function buildMockContainer(fulfillmentData: unknown) {
  const mockQuery = {
    graph: jest.fn().mockResolvedValue({ data: [fulfillmentData] })
  }

  const mockLogger = {
    info: jest.fn(),
    warn: jest.fn(),
    error: jest.fn(),
    debug: jest.fn()
  }

  return {
    resolve: jest.fn((key: string) => {
      if (key === 'query') return mockQuery
      if (key === 'logger') return mockLogger
      throw new Error(`Unknown key: ${key}`)
    }),
    __mockQuery: mockQuery,
    __mockLogger: mockLogger
  }
}

function buildEvent(fulfillmentId: string) {
  return {
    data: { id: fulfillmentId },
    name: 'delivery.created',
    metadata: {}
  }
}

describe('collection-auto-update subscriber', () => {
  beforeEach(() => {
    jest.clearAllMocks()
  })

  it('extracts catalog_sku from product metadata and publishes correct payload', async () => {
    const fulfillment = {
      order: {
        id: 'order_123',
        customer_id: 'cust_abc',
        items: [
          {
            id: 'item_1',
            quantity: 2,
            variant: {
              metadata: { condition: 'LP' },
              product: {
                metadata: { catalog_sku: 'PKM-SV06-001-EN-LP-NORMAL' }
              }
            }
          },
          {
            id: 'item_2',
            quantity: 1,
            variant: {
              metadata: {},
              product: {
                metadata: { catalog_sku: 'PKM-SV06-002-EN-NM-FOIL' }
              }
            }
          }
        ]
      }
    }

    const container = buildMockContainer(fulfillment)
    const event = buildEvent('ful_456')

    await collectionAutoUpdateHandler({
      event,
      container
    } as any)

    expect(mockPublish).toHaveBeenCalledTimes(1)
    const [channel, message] = mockPublish.mock.calls[0]
    expect(channel).toBe('order.receipt.confirmed')

    const payload = JSON.parse(message)
    expect(payload.userId).toBe('cust_abc')
    expect(payload.items).toHaveLength(2)
    expect(payload.items[0]).toEqual({
      catalogSku: 'PKM-SV06-001-EN-LP-NORMAL',
      quantity: 2,
      condition: 'LP'
    })
    expect(payload.items[1]).toEqual({
      catalogSku: 'PKM-SV06-002-EN-NM-FOIL',
      quantity: 1,
      condition: 'NM'
    })
  })

  it('skips items without catalog_sku and does not publish when no items have it', async () => {
    const fulfillment = {
      order: {
        id: 'order_789',
        customer_id: 'cust_xyz',
        items: [
          {
            id: 'item_no_sku',
            quantity: 1,
            variant: {
              metadata: {},
              product: { metadata: {} }
            }
          }
        ]
      }
    }

    const container = buildMockContainer(fulfillment)
    const event = buildEvent('ful_nope')

    await collectionAutoUpdateHandler({
      event,
      container
    } as any)

    expect(mockPublish).not.toHaveBeenCalled()
    expect(container.__mockLogger.info).toHaveBeenCalledWith(
      expect.stringContaining('No items with catalog_sku')
    )
  })

  it('logs error and does not throw on query failure', async () => {
    const mockQuery = {
      graph: jest.fn().mockRejectedValue(new Error('DB connection lost'))
    }
    const mockLogger = {
      info: jest.fn(),
      warn: jest.fn(),
      error: jest.fn(),
      debug: jest.fn()
    }
    const container = {
      resolve: jest.fn((key: string) => {
        if (key === 'query') return mockQuery
        if (key === 'logger') return mockLogger
        throw new Error(`Unknown key: ${key}`)
      })
    }

    const event = buildEvent('ful_err')

    // Should NOT throw
    await expect(
      collectionAutoUpdateHandler({ event, container } as any)
    ).resolves.toBeUndefined()

    expect(mockLogger.error).toHaveBeenCalledWith(
      expect.stringContaining('DB connection lost')
    )
    expect(mockPublish).not.toHaveBeenCalled()
  })

  it('falls back to variant metadata for catalog_sku', async () => {
    const fulfillment = {
      order: {
        id: 'order_fallback',
        customer_id: 'cust_fb',
        items: [
          {
            id: 'item_variant_sku',
            quantity: 3,
            variant: {
              metadata: {
                catalog_sku: 'MTG-MKM-050-EN-NM-NORMAL',
                condition: 'NM'
              },
              product: { metadata: {} }
            }
          }
        ]
      }
    }

    const container = buildMockContainer(fulfillment)
    const event = buildEvent('ful_fb')

    await collectionAutoUpdateHandler({
      event,
      container
    } as any)

    expect(mockPublish).toHaveBeenCalledTimes(1)
    const payload = JSON.parse(mockPublish.mock.calls[0][1])
    expect(payload.items[0].catalogSku).toBe('MTG-MKM-050-EN-NM-NORMAL')
  })
})

