import { EventEmitter } from 'events'

// Mock ioredis subscriber
const mockSubscriberEmitter = new EventEmitter()
const mockSubscribe = jest.fn((_channel: string, cb: (err: Error | null) => void) => {
  cb(null)
})

jest.mock('../config/infrastructure', () => ({
  getRedisSubscriber: jest.fn(() => ({
    subscribe: mockSubscribe,
    on: mockSubscriberEmitter.on.bind(mockSubscriberEmitter)
  }))
}))

// Mock logger
jest.mock('../config/logger', () => ({
  logger: {
    info: jest.fn(),
    warn: jest.fn(),
    error: jest.fn(),
    debug: jest.fn()
  }
}))

// Mock database
const mockCollectionFindOne = jest.fn()
const mockCollectionCreate = jest.fn()
const mockCollectionSave = jest.fn()
const mockCardFindOne = jest.fn()
const mockCardCreate = jest.fn()
const mockCardSave = jest.fn()
const mockSkuFindOne = jest.fn()

const mockTransaction = jest.fn(async (cb: (manager: any) => Promise<void>) => {
  const manager = {
    getRepository: jest.fn((entity: any) => {
      const name = entity.name || entity
      if (name === 'Collection') {
        return {
          findOne: mockCollectionFindOne,
          create: mockCollectionCreate,
          save: mockCollectionSave
        }
      }
      if (name === 'CollectionCard') {
        return {
          findOne: mockCardFindOne,
          create: mockCardCreate,
          save: mockCardSave
        }
      }
      if (name === 'CatalogSKU') {
        return {
          findOne: mockSkuFindOne
        }
      }
      return {}
    })
  }
  await cb(manager)
})

jest.mock('../config/database', () => ({
  AppDataSource: {
    transaction: mockTransaction,
    getRepository: jest.fn()
  }
}))

import { startCollectionSubscriber } from '../subscribers/collection-subscriber'
import { logger } from '../config/logger'

describe('collection-subscriber', () => {
  beforeEach(() => {
    jest.clearAllMocks()
    mockSubscriberEmitter.removeAllListeners()
  })

  function startAndGetHandler() {
    startCollectionSubscriber()
    // Extract the message handler registered on the emitter
    const messageListeners = mockSubscriberEmitter.listeners('message')
    expect(messageListeners.length).toBeGreaterThan(0)
    return messageListeners[messageListeners.length - 1] as (
      channel: string,
      message: string
    ) => void
  }

  it('creates "My Collection" when none exists and inserts CollectionCard', async () => {
    const handler = startAndGetHandler()

    // No existing collection
    mockCollectionFindOne.mockResolvedValue(null)
    const createdCollection = { id: 'col_new', userId: 'user_1', name: 'My Collection', type: 'personal' }
    mockCollectionCreate.mockReturnValue(createdCollection)
    mockCollectionSave.mockResolvedValue(createdCollection)

    // CatalogSKU resolves to a card
    mockSkuFindOne.mockResolvedValue({
      sku: 'PKM-SV06-001-EN-NM-NORMAL',
      print: { card: { id: 'card_123' } }
    })

    // No existing CollectionCard
    mockCardFindOne.mockResolvedValue(null)
    const createdCard = { id: 'cc_1', catalogSku: 'PKM-SV06-001-EN-NM-NORMAL', quantity: 1 }
    mockCardCreate.mockReturnValue(createdCard)
    mockCardSave.mockResolvedValue(createdCard)

    const payload = {
      userId: 'user_1',
      items: [{ catalogSku: 'PKM-SV06-001-EN-NM-NORMAL', quantity: 1, condition: 'NM' }]
    }

    await handler('order.receipt.confirmed', JSON.stringify(payload))

    // Wait for async processing
    await new Promise((r) => setTimeout(r, 50))

    expect(mockCollectionCreate).toHaveBeenCalledWith(
      expect.objectContaining({
        userId: 'user_1',
        name: 'My Collection',
        type: 'personal'
      })
    )
    expect(mockCardCreate).toHaveBeenCalledWith(
      expect.objectContaining({
        collectionId: 'col_new',
        cardId: 'card_123',
        catalogSku: 'PKM-SV06-001-EN-NM-NORMAL',
        quantity: 1,
        condition: 'NM'
      })
    )
  })

  it('increments quantity on existing CollectionCard with same SKU/condition', async () => {
    const handler = startAndGetHandler()

    // Existing collection
    const existingCollection = { id: 'col_exist', userId: 'user_2', name: 'My Collection', type: 'personal' }
    mockCollectionFindOne.mockResolvedValue(existingCollection)

    // CatalogSKU resolves
    mockSkuFindOne.mockResolvedValue({
      sku: 'MTG-MKM-050-EN-LP-FOIL',
      print: { card: { id: 'card_456' } }
    })

    // Existing CollectionCard with quantity 2
    const existingCard = {
      id: 'cc_exist',
      collectionId: 'col_exist',
      cardId: 'card_456',
      catalogSku: 'MTG-MKM-050-EN-LP-FOIL',
      quantity: 2,
      condition: 'LP'
    }
    mockCardFindOne.mockResolvedValue(existingCard)
    mockCardSave.mockResolvedValue({ ...existingCard, quantity: 5 })

    const payload = {
      userId: 'user_2',
      items: [{ catalogSku: 'MTG-MKM-050-EN-LP-FOIL', quantity: 3, condition: 'LP' }]
    }

    await handler('order.receipt.confirmed', JSON.stringify(payload))
    await new Promise((r) => setTimeout(r, 50))

    // Should have incremented quantity by 3 (from 2 to 5)
    expect(mockCardSave).toHaveBeenCalledWith(
      expect.objectContaining({ quantity: 5 })
    )
    expect(mockCardCreate).not.toHaveBeenCalled()
  })

  it('handles multiple items in one event', async () => {
    const handler = startAndGetHandler()

    const existingCollection = { id: 'col_multi', userId: 'user_3', name: 'My Collection', type: 'personal' }
    mockCollectionFindOne.mockResolvedValue(existingCollection)

    // First SKU resolves
    mockSkuFindOne
      .mockResolvedValueOnce({ sku: 'SKU-A', print: { card: { id: 'card_a' } } })
      .mockResolvedValueOnce({ sku: 'SKU-B', print: { card: { id: 'card_b' } } })
      .mockResolvedValueOnce(null) // Third SKU doesn't resolve

    mockCardFindOne.mockResolvedValue(null) // No existing cards
    mockCardCreate.mockImplementation((data: any) => ({ id: `cc_${data.catalogSku}`, ...data }))
    mockCardSave.mockImplementation(async (card: any) => card)

    const payload = {
      userId: 'user_3',
      items: [
        { catalogSku: 'SKU-A', quantity: 1, condition: 'NM' },
        { catalogSku: 'SKU-B', quantity: 2, condition: 'LP' },
        { catalogSku: 'SKU-MISSING', quantity: 1, condition: 'NM' }
      ]
    }

    await handler('order.receipt.confirmed', JSON.stringify(payload))
    await new Promise((r) => setTimeout(r, 50))

    // Two cards created (third SKU not found)
    expect(mockCardCreate).toHaveBeenCalledTimes(2)
    expect(logger.warn).toHaveBeenCalledWith(
      expect.stringContaining('No card found for catalogSku SKU-MISSING')
    )
  })

  it('logs error on malformed JSON without crashing', async () => {
    const handler = startAndGetHandler()

    // Should not throw
    await handler('order.receipt.confirmed', 'not valid json {{{')
    await new Promise((r) => setTimeout(r, 50))

    expect(logger.warn).toHaveBeenCalledWith(
      expect.stringContaining('Malformed JSON')
    )
    expect(mockTransaction).not.toHaveBeenCalled()
  })

  it('ignores messages from other channels', async () => {
    const handler = startAndGetHandler()

    await handler('some.other.channel', JSON.stringify({ userId: 'u', items: [] }))
    await new Promise((r) => setTimeout(r, 50))

    expect(mockTransaction).not.toHaveBeenCalled()
  })
})

